const config = $input.first().json;
const fteGroups = config.mappings?.fte_groups || [];
const newsSkills = config.mappings?.news_exception_skills || [];

const support_skills = [
  ...new Set([
    ...fteGroups.map((row) => row.skill_name),
    ...newsSkills.map((row) => row.skill_name),
  ]),
].filter(Boolean);

if (support_skills.length === 0) {
  throw new Error(
    'System Error: support skills list is empty (mappings/fte_groups.json)',
  );
}

const runDateStr = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Moscow',
}).format(new Date());
const runDate = new Date(`${runDateStr}T12:00:00Z`);
runDate.setUTCDate(runDate.getUTCDate() + 1);
const shift_date = runDate.toISOString().slice(0, 10);

return [
  {
    json: {
      ...config,
      shift_date,
      support_skills,
      support_skills_count: support_skills.length,
    },
  },
];

const ctx = $('Prepare GTD Context').first().json;
const excluded_logins = $input
  .all()
  .map((item) => item.json.agent_login)
  .filter(Boolean);

return [
  {
    json: {
      ...ctx,
      excluded_logins,
      excluded_logins_count: excluded_logins.length,
    },
  },
];

