const agents = $input.all().filter((item) => item.json.agent_login);
if (agents.length === 0) {
  return [{ json: { _no_agents: true } }];
}
return agents.map((item) => ({ json: item.json }));

const wfm = $('Process Each Agent').item.json;
const upsert = $input.first().json;
return [{ json: { ...wfm, agent_id: upsert.agent_id } }];

const row = $('Attach Agent Id').first().json;
const tx = $input.first().json;
return [{ json: { ...row, transaction_id: tx.transaction_id } }];

const mappings = $('Start').first().json.mappings;
const records = $input.all();

return records.map((item) => ({
  json: {
    transaction_id: item.json.transaction_id,
    agent_id: item.json.agent_id,
    agent_login: item.json.agent_login,
    shift_start_msk: item.json.shift_start_msk,
    is_night_shift: item.json.is_night_shift,
    shift_date: item.json.shift_date,
    wfm_user_id: item.json.wfm_user_id,
    mappings,
  },
}));
